  "description" : "Bananas are usually sold in bunches of five or six. ",
  "highlights" : [
    {
      "path" : "description",
      "texts" : [
        {
          "value" : "Bananas are usually sold in ",
          "type" : "text"
        },
        {
          "value" : "bunches",
          "type" : "hit"
        },
        {
          "value" : " of five or six. ",
          "type" : "text"
        }
      ],
      "score" : 1.2841906547546387
    }
  ]
}
